INSERT  IGNORE INTO `article` (`id`, `author`, `content`, `created_date`, `image`, `modified_date`, `short_content`, `status`, `title`, `category_id`, `user_id`) VALUES (1,'Đội ngũ tư vấn Moto Shop','<h2><strong>1. Xác định mục đích sử dụng</strong></h2>\r\n<p>Trước khi chọn xe, hãy tự hỏi: bạn đi xe chủ yếu để làm gì? Đi làm hàng ngày trong phố? Chạy đường dài liên tỉnh? Hay chỉ di chuyển ngắn trong khu dân cư? Mục đích sử dụng quyết định hơn 50% việc bạn nên chọn xe loại gì.</p>\r\n<ul>\r\n  <li><strong>Đi phố hàng ngày:</strong> Xe tay ga (scooter) là lựa chọn lý tưởng — tiện lợi, tiết kiệm xăng, dễ giữ đồ.</li>\r\n  <li><strong>Đường dài, địa hình xấu:</strong> Xe số hoặc xe côn tay cho cảm giác lái chủ động hơn, bền bỉ hơn.</li>\r\n  <li><strong>Mang vác hàng hóa:</strong> Xe số truyền thống như Honda Wave, Suzuki Axelo có độ bền cao và chi phí bảo dưỡng thấp.</li>\r\n</ul>\r\n<h2><strong>2. Cân nhắc ngân sách thực tế</strong></h2>\r\n<p>Giá xe chỉ là một phần — bạn cần tính thêm chi phí đăng ký, bảo hiểm, phụ kiện (mũ bảo hiểm, khóa chống trộm) và dự phòng bảo dưỡng 6 tháng đầu. Một chiếc xe tầm 30–45 triệu đồng thường phù hợp với đa số người dùng phổ thông.</p>\r\n<h2><strong>3. Ưu tiên thương hiệu có hệ thống bảo hành rộng</strong></h2>\r\n<p>Honda và Yamaha hiện có mạng lưới HEAD/YEAD trải rộng toàn quốc, giúp việc bảo dưỡng và thay thế phụ tùng chính hãng dễ dàng hơn. Đây là yếu tố quan trọng, đặc biệt nếu bạn ở tỉnh hoặc thường xuyên di chuyển liên vùng.</p>\r\n<h2><strong>4. Kiểm tra kỹ trước khi nhận xe</strong></h2>\r\n<p>Dù mua xe mới hay xe cũ, hãy kiểm tra các điểm sau:</p>\r\n<ul>\r\n  <li>Số khung, số máy khớp với giấy tờ</li>\r\n  <li>Đèn trước/sau, xi nhan hoạt động bình thường</li>\r\n  <li>Phanh trước/sau ăn đều, không bị lỏng</li>\r\n  <li>Không có mùi khét từ động cơ hay hộp số</li>\r\n  <li>Lốp xe không bị mòn, không phình vá</li>\r\n</ul>\r\n<h2><strong>5. Đọc kỹ hợp đồng và giấy tờ xe</strong></h2>\r\n<p>Đảm bảo bạn nhận đủ: hóa đơn mua xe, phiếu bảo hành, sổ tay hướng dẫn sử dụng. Với xe cũ, cần kiểm tra cà vẹt (giấy đăng ký xe) chính chủ và xác nhận không bị thế chấp ngân hàng trước khi thanh toán.</p>','2026-06-14 09:30:00','blog_1.jpg','2026-05-05 17:02:01','<p>Mua xe máy lần đầu dễ bị \"hoa mắt\" trước hàng chục mẫu xe trên thị trường. Bài viết này tổng hợp 5 kinh nghiệm thực tế giúp bạn chọn được chiếc xe phù hợp nhất với nhu cầu và ngân sách.</p>',1,'5 Kinh nghiệm chọn mua xe máy không thể bỏ qua',35,2),(2,'Đội ngũ kỹ thuật Moto Shop','<h2><strong>Tại sao phải bảo dưỡng định kỳ?</strong></h2>\r\n<p>Nhiều chủ xe thường bỏ qua lịch bảo dưỡng vì thấy xe vẫn chạy bình thường. Thực tế, các bộ phận bên trong động cơ đang mòn dần theo từng kilomet. Bảo dưỡng đúng lịch giúp phát hiện sớm hỏng hóc, tiết kiệm chi phí sửa chữa lớn về sau.</p>\r\n<h2><strong>Lịch bảo dưỡng chuẩn theo km</strong></h2>\r\n<h3><strong>Mỗi 1.000 km (hoặc 1 tháng)</strong></h3>\r\n<ul>\r\n  <li>Kiểm tra áp suất lốp trước/sau</li>\r\n  <li>Kiểm tra mức dầu nhớt</li>\r\n  <li>Kiểm tra phanh, đèn, xi nhan</li>\r\n  <li>Vệ sinh sơ bộ xe</li>\r\n</ul>\r\n<h3><strong>Mỗi 3.000 km (hoặc 3 tháng)</strong></h3>\r\n<ul>\r\n  <li><strong>Thay dầu nhớt</strong> — đây là việc quan trọng nhất, không nên trì hoãn</li>\r\n  <li>Vệ sinh bộ lọc gió</li>\r\n  <li>Kiểm tra, điều chỉnh dây côn/phanh</li>\r\n  <li>Kiểm tra bu-gi (spark plug)</li>\r\n</ul>\r\n<h3><strong>Mỗi 6.000 km (hoặc 6 tháng)</strong></h3>\r\n<ul>\r\n  <li>Thay lọc dầu (oil filter)</li>\r\n  <li>Thay bu-gi nếu đã dùng lâu</li>\r\n  <li>Kiểm tra hệ thống nhiên liệu, làm sạch bộ chế hòa khí/kim phun</li>\r\n  <li>Kiểm tra độ mòn lốp, thay lốp nếu cần</li>\r\n</ul>\r\n<h3><strong>Mỗi 12.000 km (hoặc 1 năm)</strong></h3>\r\n<ul>\r\n  <li>Thay dầu hộp số (với xe số, xe côn)</li>\r\n  <li>Kiểm tra toàn bộ hệ thống điện</li>\r\n  <li>Kiểm tra và tra mỡ bạc đạn bánh xe</li>\r\n  <li>Vệ sinh tổng thể động cơ</li>\r\n</ul>\r\n<h2><strong>Dấu hiệu xe cần bảo dưỡng ngay</strong></h2>\r\n<p>Không cần đợi đủ km, hãy đưa xe đến garage ngay khi thấy:</p>\r\n<ul>\r\n  <li>Xe khó nổ máy hơn bình thường</li>\r\n  <li>Tiêu hao xăng tăng đột biến</li>\r\n  <li>Có tiếng kêu lạ từ động cơ hoặc hộp số</li>\r\n  <li>Phanh bị lỏng hoặc rung giật khi thắng gấp</li>\r\n  <li>Khói xả có màu đen hoặc trắng đục</li>\r\n</ul>\r\n<p>Bảo dưỡng đúng cách không chỉ giúp xe bền mà còn đảm bảo an toàn cho bạn trên mọi hành trình.</p>','2026-06-14 09:35:00','blog_2.jpg','2026-05-05 17:02:07','<p>Xe máy bền hay mau hỏng phụ thuộc phần lớn vào thói quen bảo dưỡng định kỳ. Dưới đây là lịch bảo dưỡng chuẩn theo khuyến nghị của nhà sản xuất mà mọi chủ xe nên nắm rõ.</p>',1,'Lịch bảo dưỡng xe máy định kỳ — Đừng bỏ qua nếu muốn xe bền',35,2),(3,'Huy Trinh','<h2>Honda ra mắt Air Blade 2025 với công nghệ eSP+</h2><p>Honda Việt Nam vừa chính thức giới thiệu Honda Air Blade 2025 — phiên bản nâng cấp toàn diện với động cơ eSP+ thế hệ mới, tăng công suất lên 9.5 kW và giảm tiêu hao nhiên liệu xuống còn 1.7 lít/100km.</p><p>Xe được bổ sung màn hình LCD đa thông tin, khóa thông minh Smart Key và hệ thống phanh CBS tích hợp. Giá bán dự kiến từ 55.000.000 VNĐ, có mặt tại các đại lý ủy quyền Honda trên toàn quốc từ tháng 7/2025.</p>','2026-05-15 09:00:00','air_blade_2.jpg','2026-05-15 09:00:00','<p>Honda Việt Nam ra mắt Air Blade 2025 với động cơ eSP+ mới, tiết kiệm nhiên liệu hơn và nhiều tính năng hiện đại.</p>',1,'Honda Air Blade 2025 ra mắt: Nâng cấp toàn diện động cơ eSP+',35,2),(4,'Huy Trinh','<h2>Yamaha Exciter 2025 — Vua Côn Tay thế hệ mới</h2><p>Yamaha Motor Việt Nam vừa trình làng Exciter 2025 với thiết kế hoàn toàn mới mang phong cách R-series, động cơ VVA 155cc được tối ưu hóa cho hiệu suất và tiết kiệm nhiên liệu.</p><p>Đặc biệt, phiên bản cao cấp RC được trang bị quickshifter và đèn pha LED dạng thiên thạch. Đây là dòng xe côn tay bán chạy nhất phân khúc 150-160cc tại Việt Nam trong suốt nhiều năm liên tiếp.</p>','2026-05-20 14:30:00','yamaha_exciter155_born_to_ride.png','2026-05-20 14:30:00','<p>Yamaha Exciter 2025 ra mắt với thiết kế hoàn toàn mới, động cơ VVA 155cc cải tiến và nhiều trang bị cao cấp.</p>',1,'Yamaha Exciter 2025 lộ diện: Thiết kế mới, mạnh mẽ hơn bao giờ hết',35,2),(5,'Huy Trinh','<h2>Top 5 xe tay ga đáng mua nhất năm 2025</h2><p>Thị trường xe tay ga Việt Nam năm 2025 sôi động với nhiều model mới và cũ cạnh tranh khốc liệt. Dưới đây là 5 cái tên đáng chú ý nhất:</p><ol><li><strong>Honda Air Blade 125</strong> — Tiết kiệm, bền bỉ, giá hợp lý</li><li><strong>Yamaha NVX 155 VVA</strong> — Thể thao, mạnh mẽ, phù hợp phượt</li><li><strong>Honda SH 160i</strong> — Đẳng cấp, sang trọng, phù hợp công sở</li><li><strong>Honda Vario 160</strong> — Thực dụng, khoang chứa đồ lớn</li><li><strong>Yamaha Freego 125</strong> — Trẻ trung, kết nối thông minh</li></ol>','2026-05-25 10:00:00','category_xe_tay_ga.jpg','2026-05-25 10:00:00','<p>Tổng hợp 5 mẫu xe tay ga đáng mua nhất năm 2025 theo từng nhu cầu sử dụng.</p>',1,'Top 5 xe tay ga đáng mua nhất 2025 theo từng nhu cầu',35,2),(6,'Huy Trinh','<h2>Xe máy điện bùng nổ tại Việt Nam năm 2025</h2><p>Theo số liệu từ Hiệp hội các nhà sản xuất xe máy Việt Nam (VAMM), doanh số xe điện hai bánh tăng trưởng 45% trong quý 1/2025 so với cùng kỳ năm ngoái. VinFast, Honda và Yadea đang dẫn đầu thị phần với các dòng xe có phạm vi hoạt động từ 100–200 km/lần sạc.</p><p>Với việc xăng liên tục tăng giá và ý thức bảo vệ môi trường ngày càng cao, người tiêu dùng Việt Nam đang dần chuyển sang xe điện như một giải pháp di chuyển bền vững cho tương lai.</p>','2026-06-01 08:00:00','honda_cuv_e.webp','2026-06-01 08:00:00','<p>Doanh số xe điện hai bánh tăng 45% quý 1/2025. Xu hướng chuyển đổi sang xe điện đang diễn ra mạnh mẽ tại Việt Nam.</p>',1,'Xe máy điện bùng nổ tại Việt Nam: Tăng trưởng 45% trong quý 1/2025',35,2),(7,'Huy Trinh','<h2>Ưu đãi Hè 2025 — Mua xe, nhận quà liền tay!</h2><p>Nhân dịp hè 2025, LT Motor triển khai chương trình khuyến mãi đặc biệt áp dụng cho toàn bộ xe mới từ nay đến hết 31/07/2025:</p><ul><li><strong>Tặng ngay mũ bảo hiểm cao cấp</strong> trị giá 500.000đ cho mỗi xe mua</li><li><strong>Giảm 500.000đ</strong> phí làm đăng ký xe</li><li><strong>Bảo hiểm vật chất 1 năm miễn phí</strong> cho xe trên 50 triệu</li><li><strong>Trả góp 0% lãi suất</strong> 6 tháng đầu khi mua qua VPBank</li></ul><p><em>Áp dụng tại showroom LT Motor. Số lượng có hạn, liên hệ ngay để đăng ký!</em></p>','2026-06-01 07:00:00','slide_home_1.jpg','2026-06-01 07:00:00','<p>LT Motor khuyến mãi hè 2025: Tặng mũ bảo hiểm, giảm phí đăng ký, bảo hiểm miễn phí và trả góp 0% lãi suất 6 tháng đầu.</p>',1,'[Khuyến mãi Hè 2025] Mua xe – Tặng quà – Trả góp 0% lãi suất',36,2),(8,'Huy Trinh','<h2>Tri ân khách hàng thân thiết — Ưu đãi độc quyền tháng 6</h2><p>Để tri ân những khách hàng đã đồng hành cùng LT Motor, chúng tôi gửi tặng chương trình ưu đãi đặc biệt dành riêng cho tháng 6/2025:</p><ul><li><strong>Khách VIP</strong> (mua từ lần 2 trở lên): Giảm thêm 1.000.000đ trên giá niêm yết</li><li><strong>Giới thiệu bạn bè:</strong> Nhận ngay 500.000đ cho mỗi khách hàng giới thiệu thành công mua xe</li><li><strong>Sinh nhật tháng 6:</strong> Giảm 300.000đ phí dịch vụ bảo dưỡng và tặng quà bất ngờ</li></ul><p>Liên hệ hotline <strong>0334 018 518</strong> để biết thêm chi tiết và đăng ký nhận ưu đãi.</p>','2026-06-03 09:00:00','slide_home_2.jpg','2026-06-03 09:00:00','<p>Chương trình tri ân khách hàng thân thiết tháng 6: Giảm giá VIP, thưởng giới thiệu bạn bè và ưu đãi sinh nhật.</p>',1,'Tri ân khách hàng thân thiết: Ưu đãi độc quyền tháng 6/2025',36,2),(9,'Huy Trinh','<h2>Flash Sale cuối tuần — Giảm đến 3 triệu đồng!</h2><p>Mỗi Thứ 7 và Chủ Nhật, LT Motor áp dụng chương trình Flash Sale với những ưu đãi cực hấp dẫn:</p><ul><li>Xe tay ga Honda, Yamaha dưới 40 triệu: <strong>Giảm 1.000.000đ</strong> khi thanh toán tiền mặt</li><li>Xe tay ga trên 40 triệu: <strong>Giảm 2.000.000đ</strong> khi thanh toán tiền mặt</li><li>Xe côn tay, xe phân khúc lớn: <strong>Giảm 3.000.000đ</strong> khi đặt cọc trước 3 ngày</li></ul><p><em>Không kết hợp với các khuyến mãi khác. Áp dụng tại showroom LT Motor.</em></p>','2026-06-04 08:00:00','slide_home_3.jpg','2026-06-04 08:00:00','<p>Flash Sale cuối tuần mỗi Thứ 7 và Chủ Nhật: Giảm từ 1 đến 3 triệu đồng tùy dòng xe khi thanh toán tiền mặt.</p>',1,'Flash Sale cuối tuần: Giảm đến 3.000.000đ – Chỉ tại LT Motor!',36,2),(10,'Huy Trinh','<h2>Trả góp 0% lãi suất — Sở hữu xe ngay hôm nay!</h2><p>LT Motor hợp tác với VPBank và Techcombank triển khai gói trả góp đặc biệt áp dụng từ 01/06 đến 31/08/2025:</p><ul><li>Lãi suất <strong>0%</strong> trong 6 tháng đầu</li><li>Trả trước chỉ từ <strong>20%</strong> giá trị xe</li><li>Thủ tục đơn giản, duyệt nhanh trong <strong>1 giờ</strong></li><li>Không cần tài sản thế chấp với khoản vay dưới 50 triệu</li><li>Áp dụng cho tất cả các dòng xe tại showroom</li></ul><p>Chỉ cần CCCD và bằng lái xe, bạn đã có thể sở hữu chiếc xe mơ ước ngay hôm nay!</p>','2026-06-04 10:00:00','quy-trinh-mua-xe-motor.png','2026-06-04 10:00:00','<p>Gói trả góp 0% lãi suất 6 tháng đầu, trả trước chỉ 20%, duyệt nhanh trong 1 giờ áp dụng đến 31/08/2025.</p>',1,'Gói trả góp 0% lãi suất 6 tháng: Sở hữu xe mơ ước với chi phí tối thiểu',36,2),(11,'Huy Trinh','<h2>Tuyển dụng Nhân viên Tư vấn Bán hàng xe máy</h2><p>LT Motor đang mở rộng đội ngũ và tìm kiếm những ứng viên nhiệt huyết, đam mê xe máy để đảm nhận vị trí <strong>Nhân viên Tư vấn Bán hàng</strong>.</p><h3>Mô tả công việc</h3><ul><li>Tư vấn, giới thiệu sản phẩm xe máy cho khách hàng tại showroom</li><li>Theo dõi và chăm sóc khách hàng tiềm năng</li><li>Hỗ trợ khách hàng làm thủ tục mua xe, đăng ký, bảo hiểm</li><li>Đạt doanh số theo chỉ tiêu hàng tháng</li></ul><h3>Yêu cầu</h3><ul><li>Tốt nghiệp THPT trở lên, ưu tiên chuyên ngành kinh tế</li><li>Có đam mê với xe máy</li><li>Kỹ năng giao tiếp tốt, ngoại hình ưa nhìn</li><li>Có bằng lái xe A1 trở lên</li></ul><h3>Quyền lợi</h3><ul><li>Lương cơ bản 6–8 triệu + hoa hồng không giới hạn</li><li>Đóng đầy đủ BHXH, BHYT, BHTN</li><li>Thưởng theo doanh số tháng/quý/năm</li></ul>','2026-05-28 08:00:00','honda_sh160i.png','2026-05-28 08:00:00','<p>LT Motor tuyển Nhân viên Tư vấn Bán hàng: Lương 6–8 triệu + hoa hồng, môi trường năng động, cơ hội thăng tiến rõ ràng.</p>',1,'[Tuyển dụng] Nhân viên Tư vấn Bán hàng xe máy – Thu nhập 15-25 triệu/tháng',37,2),(12,'Huy Trinh','<h2>Tuyển Kỹ thuật viên Bảo dưỡng Xe máy</h2><p>Nhằm nâng cao chất lượng dịch vụ hậu mãi, LT Motor cần tuyển <strong>Kỹ thuật viên Bảo dưỡng</strong> có tay nghề và kinh nghiệm thực tế.</p><h3>Mô tả công việc</h3><ul><li>Thực hiện bảo dưỡng định kỳ, sửa chữa xe máy các hãng Honda, Yamaha, Suzuki</li><li>Chuẩn đoán lỗi và tư vấn phương án sửa chữa cho khách hàng</li><li>Ghi chép phiếu sửa chữa, quản lý phụ tùng thay thế</li></ul><h3>Yêu cầu</h3><ul><li>Tốt nghiệp trường kỹ thuật chuyên ngành cơ khí, điện tử hoặc tương đương</li><li>Có ít nhất 1 năm kinh nghiệm sửa chữa xe máy</li><li>Ưu tiên có chứng chỉ kỹ thuật của Honda/Yamaha</li><li>Chịu khó, cẩn thận và có tinh thần trách nhiệm cao</li></ul><h3>Quyền lợi</h3><ul><li>Lương cơ bản 8–12 triệu tùy kinh nghiệm</li><li>Thưởng năng suất hàng tháng</li><li>Được đào tạo kỹ thuật chính hãng tại Honda/Yamaha</li></ul>','2026-06-01 09:00:00','exciter_155_1.jpg','2026-06-01 09:00:00','<p>LT Motor tuyển Kỹ thuật viên Bảo dưỡng xe máy: Lương 8–12 triệu, đào tạo chính hãng, môi trường chuyên nghiệp.</p>',1,'[Tuyển dụng] Kỹ thuật viên Bảo dưỡng xe máy – Lương 8-12 triệu',37,2),(13,'Huy Trinh','<h2>Tuyển Nhân viên Chăm sóc Khách hàng (CSKH)</h2><p>LT Motor đang tìm kiếm <strong>Nhân viên CSKH</strong> năng động, có kỹ năng giao tiếp tốt để hỗ trợ khách hàng trước và sau bán hàng.</p><h3>Mô tả công việc</h3><ul><li>Tiếp nhận và xử lý yêu cầu, khiếu nại của khách hàng qua điện thoại, Zalo, Facebook</li><li>Theo dõi đơn hàng, phối hợp giao xe đúng hẹn</li><li>Nhắc lịch bảo dưỡng, chăm sóc khách hàng cũ</li><li>Khảo sát sự hài lòng sau khi mua xe</li></ul><h3>Yêu cầu</h3><ul><li>Tốt nghiệp Cao đẳng trở lên</li><li>Kỹ năng giao tiếp xuất sắc, giọng nói rõ ràng, dễ nghe</li><li>Thành thạo máy tính văn phòng</li><li>Kinh nghiệm CSKH hoặc telesales là lợi thế</li></ul><h3>Quyền lợi</h3><ul><li>Lương cơ bản 6–8 triệu + KPI bonus</li><li>Giờ làm việc linh hoạt (hành chính hoặc ca)</li><li>Môi trường trẻ trung, thân thiện</li></ul>','2026-06-03 08:30:00','image-tuyendung-ltmoto.jpg','2026-06-12 23:51:08','<p>LT Motor tuyển Nhân viên CSKH: Lương 6–8 triệu + KPI bonus, giờ linh hoạt, môi trường trẻ trung và năng động.</p>',1,'[Tuyển dụng] Nhân viên Chăm sóc Khách hàng – Giờ làm việc linh hoạt',37,1);
